import{_ as a,c as s,a1 as t,o as e}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Thu thập thông tin sử dụng Metasploit","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md"}'),p={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md"};function c(o,n,i,l,h,r){return e(),s("div",null,n[0]||(n[0]=[t(`<h1 id="thu-thap-thong-tin-su-dung-metasploit" tabindex="-1">Thu thập thông tin sử dụng Metasploit <a class="header-anchor" href="#thu-thap-thong-tin-su-dung-metasploit" aria-label="Permalink to &quot;Thu thập thông tin sử dụng Metasploit&quot;">​</a></h1><p>Metasploit Framework là công cụ cung cấp thông tin về các lỗ hổng bảo mật và hỗ trợ trong kiểm thử xâm nhập và phát triển chữ ký IDS. <em>Kho lưu trữ chính thức:</em> <a href="https://github.com/rapid7/metasploit-framework" target="_blank" rel="noreferrer">https://github.com/rapid7/metasploit-framework</a></p><p><strong>Phiên bản Metasploit: 5.0.59-dev</strong></p><p>Metasploit có thể được sử dụng để kiểm tra lỗ hổng của hệ thống máy tính hoặc để xâm nhập vào các hệ thống từ xa. <strong>Lab này sẽ trình bày cách trích xuất thông tin sử dụng Metasploit Framework.</strong></p><h2 id="tong-quan-ve-metasploit" tabindex="-1">Tổng quan về Metasploit: <a class="header-anchor" href="#tong-quan-ve-metasploit" aria-label="Permalink to &quot;Tổng quan về Metasploit:&quot;">​</a></h2><p>Metasploit Framework là một dự án mã nguồn mở hỗ trợ công việc của kẻ tấn công, người viết exploit và payload. Một ưu điểm lớn của framework là cách tiếp cận mô-đun, cho phép kết hợp bất kỳ exploit nào với bất kỳ payload nào.</p><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Cách xác định lỗ hổng và rò rỉ thông tin.</li><li>Trích xuất thông tin chính xác về mạng.</li></ul><hr><h2 id="thiet-lap-metasploit" tabindex="-1">Thiết lập Metasploit <a class="header-anchor" href="#thiet-lap-metasploit" aria-label="Permalink to &quot;Thiết lập Metasploit&quot;">​</a></h2><p>Đăng nhập vào máy <strong>Kali Linux</strong> và mở cửa sổ <strong>Terminal</strong>.</p><p>Khởi động dịch vụ cơ sở dữ liệu PostgreSQL để liên kết với Metasploit:</p><p><code>service postgresql start</code></p><p>Bây giờ gõ <code>msfconsole</code> để khởi chạy Metasploit.</p><p><code>msfconsole</code></p><p>Kiểm tra xem Metasploit đã kết nối với cơ sở dữ liệu thành công chưa:</p><p><code>db_status</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] postgresql selected, no connection</span></span></code></pre></div><p>Nếu bạn nhận được thông báo này, có nghĩa là cơ sở dữ liệu chưa kết nối đúng với msf. Để khắc phục, gõ <code>exit</code> để thoát Metasploit. Sau đó, để khởi tạo cơ sở dữ liệu, gõ:</p><p><code>msfdb init</code></p><p>Sau đó, khởi động lại dịch vụ postgresql:</p><p><code>service postgresql restart</code></p><p>Khởi chạy lại Metasploit và chạy <code>db_status</code> để kiểm tra trạng thái cơ sở dữ liệu:</p><p><code>msfconsole</code><code>db_status</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Connected to msf. Connection type: postgresql.</span></span></code></pre></div><p>Bây giờ cơ sở dữ liệu đã kết nối thành công với msf.</p><h2 id="tim-cac-host-đang-hoat-đong" tabindex="-1">Tìm các host đang hoạt động <a class="header-anchor" href="#tim-cac-host-đang-hoat-đong" aria-label="Permalink to &quot;Tìm các host đang hoạt động&quot;">​</a></h2><p>Tôi khuyên bạn nên khởi động một vài VM trong Lab của bạn. Trong trường hợp của tôi, tôi đã khởi động:</p><ul><li>Ubuntu Metasploitable</li><li>Windows 7 SP1</li><li>Windows Server 2012 R2</li></ul><p>Để quét subnet, chúng ta có thể sử dụng <strong>Nmap</strong>:</p><p><code>nmap -O -oX Test 10.0.2.0/24</code></p><p>Nmap bắt đầu quét subnet và hiển thị kết quả trên màn hình. Lệnh <code>-oX Test</code> của Nmap có nghĩa là <strong>output ra file XML</strong> tên là <strong>Test</strong>.</p><p>Chúng ta có thể nhập kết quả Nmap vào cơ sở dữ liệu:</p><p><code>db_import Test</code></p><p>Để xem các host và chi tiết của chúng được Nmap khám phá, gõ:</p><p><code>hosts</code> ... <em>(Kiểm tra phiên bản OS, địa chỉ IP và MAC).</em></p><p>Tôi sẽ chọn Windows Server 2012, mà tôi đã quét để kiểm tra các dịch vụ đang chạy trên hệ thống này.</p><p><code>db_nmap -sS -A 10.0.2.28</code></p><p>Nmap bắt đầu footprint hệ thống và liệt kê chi tiết OS.</p><p><code>db_nmap</code> khởi động quét Nmap và kết quả sẽ được lưu tự động vào cơ sở dữ liệu của chúng ta.</p><p>Gõ <code>services</code> hoặc <code>db_services</code> để lấy toàn bộ danh sách dịch vụ đang chạy trên host.</p><p><code>db_services</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2734644f73fe43d2b99b56a03fb4bab3b01acf20/services-nmap-scan.png" alt="alt text" title="Nmap Services Scan"></p><h2 id="quet-cong-va-dich-vu-mo" tabindex="-1">Quét cổng và dịch vụ mở <a class="header-anchor" href="#quet-cong-va-dich-vu-mo" aria-label="Permalink to &quot;Quét cổng và dịch vụ mở&quot;">​</a></h2><p>Tìm kiếm module <strong>portscan</strong>:</p><p><code>search portscan</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#  Name                                    Disclosure Date  Rank    Check  Description</span></span>
<span class="line"><span>-  ----                                    ---------------  ----    -----  -----------</span></span>
<span class="line"><span>0  auxiliary/scanner/http/wordpress_pingback_access         normal  Yes    Wordpress Pingback Locator</span></span>
<span class="line"><span>1  auxiliary/scanner/natpmp/natpmp_portscan                 normal  Yes    NAT-PMP External Port Scanner</span></span>
<span class="line"><span>2  auxiliary/scanner/portscan/ack                           normal  Yes    TCP ACK Firewall Scanner</span></span>
<span class="line"><span>3  auxiliary/scanner/portscan/ftpbounce                     normal  Yes    FTP Bounce Port Scanner</span></span>
<span class="line"><span>4  auxiliary/scanner/portscan/syn                           normal  Yes    TCP SYN Port Scanner</span></span>
<span class="line"><span>5  auxiliary/scanner/portscan/tcp                           normal  Yes    TCP Port Scanner</span></span>
<span class="line"><span>6  auxiliary/scanner/portscan/xmas                          normal  Yes    TCP &quot;XMas&quot; Port Scanner</span></span>
<span class="line"><span>7  auxiliary/scanner/sap/sap_router_portscanner             normal  No     SAPRouter Port Scanner</span></span></code></pre></div><p>Chọn <strong>scanner/portscan/syn</strong>:</p><p><code>use scanner/portscan/syn</code></p><p>Bây giờ chúng ta cần xem các tùy chọn module:</p><p><code>show options</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name       Current Setting  Required</span></span>
<span class="line"><span>----       ---------------  --------</span></span>
<span class="line"><span>BATCHSIZE  256              yes</span></span>
<span class="line"><span>DELAY      0                yes</span></span>
<span class="line"><span>INTERFACE                   no</span></span>
<span class="line"><span>JITTER     0                yes</span></span>
<span class="line"><span>PORTS      1-10000          yes</span></span>
<span class="line"><span>RHOSTS                      yes</span></span>
<span class="line"><span>SNAPLEN    65535            yes</span></span>
<span class="line"><span>THREADS    1                yes</span></span>
<span class="line"><span>TIMEOUT    500              yes</span></span></code></pre></div><p>Đặt <code>RHOSTS</code> thành mục tiêu và <code>THREADS</code> thành <code>100</code></p><p><code>set RHOSTS 10.0.2.23</code><code>set THREADS 100</code></p><p>Gõ <code>run</code> để khởi chạy module.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[+]  TCP OPEN 10.0.2.23:53</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:80</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:88</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:135</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:139</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:389</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:443</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:445</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:464</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:593</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:636</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Module này sẽ liệt kê mọi dịch vụ TCP đang mở bằng cách sử dụng quét SYN thô.</p><p>Tiếp theo, hãy tìm phiên bản SMB. Tải module <strong>scanner/smb/smb_version</strong>:</p><p><code>use scanner/smb/smb_version</code></p><p>Gõ <code>show options</code> để xem cấu hình.</p><p>Đặt <code>RHOSTS</code> thành mục tiêu và <code>THREADS</code> thành <code>100</code></p><p><code>set RHOSTS 10.0.2.23</code><code>set THREADS 100</code></p><p>Gõ <code>run</code> để khởi chạy module.</p><p>Bây giờ gõ <code>hosts</code> và quan sát trường <strong>os_flavor</strong> của host bạn đã quét trong subnet.</p><p>Kết luận: Bạn có thể thu thập các thông báo lỗi khác nhau để tìm hiểu về lỗ hổng, và ghi lại thông tin được tiết lộ về mạng.</p>`,67)]))}const u=a(p,[["render",c]]);export{g as __pageData,u as default};
